```javascript
// Replace dotenv with AWS Secrets Manager
const { SecretsManager } = require('@aws-sdk/client-secrets-manager');

// Initialize client
const secretsClient = new SecretsManager({ region: process.env.AWS_REGION });

async function getSecret(secretName) {
  try {
    const response = await secretsClient.getSecretValue({ SecretId: secretName });
    return JSON.parse(response.SecretString);
  } catch (error) {
    console.error('Failed to retrieve secret:', error);
    throw error;
  }
}

// Usage in your app
async function initApp() {
  try {
    const dbCredentials = await getSecret('production/db-credentials');
    // Use credentials to connect to database
  } catch (error) {
    console.error('Failed to initialize app:', error);
    process.exit(1);
  }
}
```

**Option B: Proper dotenv Implementation with Git Protection**

```javascript
// Improved dotenv usage with validation
require('dotenv').config({ path: '.env' });

// Validate required environment variables
const requiredEnvVars = [
  'DATABASE_URL',
  'AWS_ACCESS_KEY_ID',
  'AWS_SECRET_ACCESS_KEY',
  'ANTHROPIC_API_KEY',
  'STRIPE_SECRET_KEY'
];

