```

### 2. Use Short-Lived Credentials

```javascript
// For AWS, use IAM roles instead of long-term access keys
// Or use temporary credentials
const { STS } = require('@aws-sdk/client-sts');

async function getTemporaryCredentials() {
  const sts = new STS({ region: 'us-east-1' });
  const role = await sts.assumeRole({
    RoleArn: process.env.AWS_ROLE_ARN,
    RoleSessionName: 'app-session'
  });
