const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const cors = require('cors');

// Rate limiting to prevent brute force attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per window
  message: {
    error: 'Too many requests from this IP, please try again later.',
    code: 'RATE_LIMIT_EXCEEDED'
  },
  standardHeaders: true, // Return rate limit info in the RateLimit-* headers
  legacyHeaders: false, // Disable the X-RateLimit-* headers
});

// CORS configuration - restrict to known domains
const corsOptions = {
  origin: function (origin, callback) {
    const allowedOrigins = [
      'https://yourproductiondomain.com',
      'https://yoursite.vercel.app',
      'http://localhost:3000' // Only for development
    ];

    // Allow requests with no origin (like mobile apps, curl, etc.)
    if (!origin) return callback(null, true);

    if (allowedOrigins.indexOf(origin) !== -1) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  },
  credentials: true,
  optionsSuccessStatus: 200
};

// Security headers using Helmet
const securityHeaders = helmet({
  // Basic Helmet configuration
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'", "'unsafe-inline'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "*.amazonaws.com"],
      connectSrc: ["'self'", "*.amazonaws.com", "*.anthropic.com"],
      fontSrc: ["'self'", "data:"],
      objectSrc: ["'none'"]
    }
  },
  // Hide powered-by header
  hidePoweredBy: {
    setTo: 'PHP 4.2.0' // Obfuscate server technology
  },
  // Prevent clickjacking
  frameguard: {
    action: 'deny'
  },
  // Enable XSS protection
  xssFilter: true,
  // Disable X-Content-Type-Options
  noSniff: true,
  // Strict transport security
  hsts: {
    maxAge: 31536000, // 1 year
    includeSubDomains: true,
    preload: true
  }
});

// Security audit middleware
const securityAudit = (req, res, next) => {
  // Log security-relevant information
  const securityContext = {
    timestamp: new Date().toISOString(),
    method: req.method,
    url: req.url,
    ip: req.ip || req.connection.remoteAddress,
    userAgent: req.get('User-Agent'),
    referer: req.get('Referer'),
    origin: req.get('Origin')
  };

  console.log('SECURITY_AUDIT:', JSON.stringify(securityContext));
  next();
};

// Error handling for security middleware
const securityErrorHandler = (err, req, res, next) => {
  if (err.message.includes('CORS')) {
    return res.status(403).json({
      error: 'Access denied by CORS policy',
      code: 'CORS_NOT_ALLOWED'
    });
  }
  next(err);
};

module.exports = {
  limiter,
  corsOptions,
  securityHeaders,
  securityAudit,
  securityErrorHandler
};

