// Input validation middleware

// Sanitize string input
const sanitizeString = (str) => {
  if (typeof str !== 'string') return str;

  // Remove potentially dangerous characters
  return str
    .trim()
    .replace(/<script.*?>.*?<\/script>/gi, '') // Remove script tags
    .replace(/javascript:/gi, '') // Remove javascript: protocol
    .replace(/on\w+\s*=|data:text\//gi, '') // Remove event handlers and data URLs
    .substring(0, 1000); // Limit length
};

// Validate email format
const isValidEmail = (email) => {
  if (!email || typeof email !== 'string') return false;

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email.trim()) && email.trim().length <= 254;
};

// Validate ID parameter (numeric)
const isValidId = (id) => {
  const num = Number(id);
  return !isNaN(num) && num > 0 && num < 1000000 && Number.isInteger(num);
};

// Middleware to validate and sanitize user input
const validateUserInput = (req, res, next) => {
  // Sanitize query parameters
  if (req.query) {
    Object.keys(req.query).forEach(key => {
      if (typeof req.query[key] === 'string') {
        req.query[key] = sanitizeString(req.query[key]);
      }
    });
  }

  // Sanitize body parameters
  if (req.body) {
    Object.keys(req.body).forEach(key => {
      if (typeof req.body[key] === 'string') {
        req.body[key] = sanitizeString(req.body[key]);
      }
    });
  }

  // Sanitize URL parameters
  if (req.params) {
    Object.keys(req.params).forEach(key => {
      if (typeof req.params[key] === 'string') {
        req.params[key] = sanitizeString(req.params[key]);
      }
    });
  }

  next();
};

// Route-specific validation middleware
const validateUserId = (req, res, next) => {
  const { id } = req.params;

  if (!id) {
    return res.status(400).json({
      error: 'User ID is required',
      code: 'MISSING_USER_ID'
    });
  }

  if (!isValidId(id)) {
    return res.status(400).json({
      error: 'Invalid user ID format',
      code: 'INVALID_USER_ID'
    });
  }

  // Store validated ID as number
  req.params.userId = Number(id);
  next();
};

// Email validation middleware
const validateEmail = (req, res, next) => {
  const email = req.body?.email || req.query?.email;

  if (email && !isValidEmail(email)) {
    return res.status(400).json({
      error: 'Invalid email format',
      code: 'INVALID_EMAIL'
    });
  }

  next();
};

module.exports = {
  validateUserInput,
  validateUserId,
  validateEmail,
  isValidEmail,
  isValidId,
  sanitizeString
};

