#### 2. Implement Proper Secrets Management

Instead of using `.env` files, integrate with a secrets manager:

```javascript
// Option 1: AWS Secrets Manager (if running on AWS)
const AWS = require('aws-sdk');
const secretsManager = new AWS.SecretsManager();

async function getSecret(secretName) {
  try {
    const data = await secretsManager.getSecretValue({ SecretId: secretName }).promise();
    return JSON.parse(data.SecretString);
  } catch (error) {
    console.error('Error retrieving secret:', error);
    throw error;
  }
}

// Option 2: Hashicorp Vault
const client = require('node-vault')({
  apiVersion: 'v1',
  endpoint: process.env.VAULT_ADDR,
});

async function getVaultSecret(path) {
  try {
    const result = await client.read(path);
    return result.data;
  } catch (error) {
    console.error('Error reading from Vault:', error);
    throw error;
  }
}
```

#### 3. Secure Development Workflow

Implement a secure approach for handling test secrets:

```javascript
// config/secrets.js
let secrets = {};

// Determine environment
const ENV = process.env.NODE_ENV || 'development';

if (ENV === 'test' || ENV === 'development') {
  try {
    // Only load local env file in dev/test
    require('dotenv').config({ 
      path: ENV === 'test' ? '.env.test' : '.env' 
    });

    // Override with environment variables if they exist
    secrets = {
      databaseUrl: process.env.DATABASE_URL,
      awsKeyId: process.env.AWS_ACCESS_KEY_ID,
      awsSecretKey: process.env.AWS_SECRET_ACCESS_KEY,
      anthropicApiKey: process.env.ANTHROPIC_API_KEY,
      stripeSecretKey: process.env.STRIPE_SECRET_KEY,
      logfireToken: process.env.LOGFIRE_TOKEN
    };
  } catch (error) {
    console.warn('Could not load .env file, falling back to process.env');
  }
} else {
  // Production - MUST use secrets manager
  if (process.env.USE_SECRETS_MANAGER !== 'true') {
    throw new Error('Production environment must use secrets manager');
  }

  // Load from secrets manager
  secrets = await loadFromSecretsManager();
}

function validateSecrets(secrets) {
  const required = ['databaseUrl', 'awsKeyId', 'awsSecretKey'];
  const missing = required.filter(key => !secrets[key]);

  if (missing.length > 0) {
    throw new Error(`Missing required secrets: ${missing.join(', ')}`);
  }

  // Validate secret patterns
  if (secrets.awsKeyId && !secrets.awsKeyId.startsWith('AKIA')) {
    throw new Error('Invalid AWS Key ID format');
  }
}

module.exports = { secrets, validateSecrets };
```

#### 4. Update app.js to Use the Secure Configuration

