```

#### 6. Implement Environment-Based Configuration

```javascript
// config/index.js
const ENV = process.env.NODE_ENV || 'development';

const configs = {
  development: {
    databaseUrl: process.env.DATABASE_URL || 'postgres://localhost:5432/devdb',
